import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.NoSuchElementException;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import com.google.gson.internal.$Gson$Types;

class GsonTypesTest {

  private static Method indexOfMethod;

  @BeforeAll
  static void setUp() throws NoSuchMethodException {
    indexOfMethod = $Gson$Types.class.getDeclaredMethod("indexOf", Object[].class, Object.class);
    indexOfMethod.setAccessible(true);
  }

  @Test
  void indexOf_returnsIndexWhenElementFound() throws IllegalAccessException, IllegalArgumentException, InvocationTargetException {
    String[] array = {"a", "b", "c"};
    Object toFind = "b";

    int index = (int) indexOfMethod.invoke(null, (Object) array, toFind);

    assertEquals(1, index);
  }

  @Test
  void indexOf_returnsZeroWhenFirstElementMatches() throws IllegalAccessException, IllegalArgumentException, InvocationTargetException {
    Integer[] array = {10, 20, 30};
    Object toFind = 10;

    int index = (int) indexOfMethod.invoke(null, (Object) array, toFind);

    assertEquals(0, index);
  }

  @Test
  void indexOf_returnsLastIndexWhenLastElementMatches() throws IllegalAccessException, IllegalArgumentException, InvocationTargetException {
    Double[] array = {1.1, 2.2, 3.3};
    Object toFind = 3.3;

    int index = (int) indexOfMethod.invoke(null, (Object) array, toFind);

    assertEquals(2, index);
  }

  @Test
  void indexOf_throwsNoSuchElementExceptionWhenNotFound() {
    String[] array = {"x", "y", "z"};
    Object toFind = "a";

    NoSuchElementException thrown = assertThrows(NoSuchElementException.class, () -> {
      try {
        indexOfMethod.invoke(null, (Object) array, toFind);
      } catch (InvocationTargetException e) {
        // unwrap the underlying exception thrown by the method
        throw e.getCause();
      }
    });

    assertNotNull(thrown);
  }

  @Test
  void indexOf_throwsNullPointerExceptionWhenToFindIsNull() {
    String[] array = {"a", "b", "c"};
    Object toFind = null;

    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      try {
        indexOfMethod.invoke(null, (Object) array, toFind);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });

    assertNotNull(thrown);
  }

  @Test
  void indexOf_throwsNullPointerExceptionWhenArrayIsNull() {
    Object[] array = null;
    Object toFind = "a";

    NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
      try {
        indexOfMethod.invoke(null, (Object) array, toFind);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });

    assertNotNull(thrown);
  }

  @Test
  void indexOf_throwsNoSuchElementExceptionWhenArrayEmpty() {
    String[] array = new String[0];
    Object toFind = "a";

    NoSuchElementException thrown = assertThrows(NoSuchElementException.class, () -> {
      try {
        indexOfMethod.invoke(null, (Object) array, toFind);
      } catch (InvocationTargetException e) {
        throw e.getCause();
      }
    });

    assertNotNull(thrown);
  }
}
